    86|/** Map a thrown gateway error into a coarse class. */
    87|export function classifyProviderFailure(error: unknown): IVXProviderFailureClass {
    88|  if (!error) return 'unknown';
    89|  const name = error instanceof Error ? error.name : '';
    90|  const message = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
    91|  const statusMatch = message.match(/status=(\d{3})/);
    92|  const status = statusMatch ? Number.parseInt(statusMatch[1], 10) : null;
    93|
    94|  if (name === 'IVXAIGatewayTimeoutError' || message.includes('timed out') || message.includes('etimedout')) {
    95|    return 'timeout';
    96|  }
    97|  if (status === 401 || status === 403 || message.includes('unauthor') || message.includes('forbidden')) {
    98|    return 'auth';
    99|  }
   100|  if (status === 429 || message.includes('rate-limit') || message.includes('rate limit')) {
   101|    return 'rate_limit';
   102|  }
   103|  if (message.includes('insufficient_quota') || message.includes('quota')) {
   104|    return 'quota';
   105|  }
   106|  if (status && status >= 500) {
   107|    return 'server_error';
   108|  }
   109|  if (status === 400 || status === 422) {
   110|    return 'bad_request';
   111|  }
   112|  if (message.includes('econnreset') || message.includes('fetch failed') || message.includes('network')) {
   113|    return 'network';
   114|  }
   115|  return 'unknown';
