   244|export async function attemptProviderFallback(input: FallbackInput): Promise<IVXProviderInvocationResult | null> {
   245|  const chain: { name: IVXProviderName; run: (i: FallbackInput) => Promise<IVXProviderInvocationResult> }[] = [];
   246|  if (hasEnv('OPENAI_API_KEY')) chain.push({ name: 'openai_direct', run: callOpenAIDirect });
   247|  if (hasEnv('ANTHROPIC_API_KEY')) chain.push({ name: 'anthropic_direct', run: callAnthropicDirect });
